     1→import { formatSizes } from '@utils/formatting.util';
     2→
     3→import {
     4→	AlgoliaRelatedProductHit,
     5→	IProductColor,
     6→} from '@interfaces/algolia-hits.interface';
     7→import { IRelatedProduct } from '@interfaces/related-product.interface';
     8→
     9→export function assignRandomColorsToProducts(
    10→	products: IRelatedProduct[],
    11→	availableColorsMap: Map<number, IProductColor[]>,
    12→): IRelatedProduct[] {
    13→	return products.map((product) =>
    14→		assignRandomColorToProduct(product, availableColorsMap.get(product.style_id)),
    15→	);
    16→}
    17→
    18→export function assignRandomColorToProduct(
    19→	product: IRelatedProduct,
    20→	availableColors?: IProductColor[],
    21→): IRelatedProduct {
    22→	if (!availableColors || availableColors.length === 0) {
    23→		return product;
    24→	}
    25→
    26→	const randomColor = getRandomColorFromArray(availableColors);
    27→
    28→	if (!randomColor) {
    29→		return product;
    30→	}
    31→
    32→	return {
    33→		...product,
    34→		color: randomColor.id,
    35→		image_src: randomColor.image_url ?? product.image_src,
    36→	};
    37→}
    38→
    39→export function getRandomColorFromArray(
    40→	colors: IProductColor[],
    41→): IProductColor | undefined {
    42→	if (!Boolean(colors) || colors.length === 0) {
    43→		return undefined;
    44→	}
    45→
    46→	return colors[Math.floor(Math.random() * colors.length)];
    47→}
    48→
    49→export function mapHitToRelatedProductWithRandomColor(hit: AlgoliaRelatedProductHit): {
    50→	product: IRelatedProduct;
    51→	availableColors: IProductColor[];
    52→} {
    53→	const randomColor = getRandomColorFromArray(hit.colors);
    54→	const selectedColor = randomColor ?? hit.colors[0];
    55→	const sizing = formatSizes({ sizes: hit.sizes });
    56→
    57→	const product: IRelatedProduct = {
    58→		color: selectedColor?.id ?? 0,
    59→		link: hit.link.path || '',
    60→		sizing,
    61→		sizes: hit.sizes,
    62→		min_qty: Boolean(hit.no_minimum) ? 1 : Number(hit.minimum_quantity) || 0,
    63→		complement_badge: null,
    64→		rating_score: String(hit.rating_score || ''),
    65→		rating_count: String(hit.rating_count || ''),
    66→		name: String(hit.name || ''),
    67→		style_id: Number(hit.product_id),
    68→		decoration_method: String(hit.decoration_method || ''),
    69→		primary_category_id: hit.primary_category_id ?? null,
    70→		primary_category_name: String(hit.primary_category_name || ''),
    71→		default_quote_qty: Number(hit.default_quote_qty || 1),
    72→		style_type: hit.style_type,
    73→		image_src: String(selectedColor?.image_url ?? '') || hit.style_card_image_url || '',
    74→		broad_category_names: Array.isArray(hit.broad_category_names)
    75→			? hit.broad_category_names
    76→			: [],
    77→		sub_category_names: Array.isArray(hit.sub_category_names)
    78→			? hit.sub_category_names
    79→			: [],
    80→		turn_time: Number(hit.turn_time),
    81→		rush_turn_time: Number(hit.rush_turn_time),
    82→		default_unit_prices: Array.isArray(hit.default_unit_prices)
    83→			? hit.default_unit_prices
    84→			: [],
    85→		brand: hit.brand ?? [],
    86→	};
    87→
    88→	return {
    89→		product,
    90→		availableColors: hit.colors,
    91→	};
    92→}
    93→

