export function assignRandomColorsToProducts(
	products: IRelatedProduct[],
	availableColorsMap: Map<number, IProductColor[]>,
): IRelatedProduct[] {
	return products.map((product) =>
		assignRandomColorToProduct(product, availableColorsMap.get(product.style_id)),
	);
}

export function assignRandomColorToProduct(
	product: IRelatedProduct,
	availableColors?: IProductColor[],
): IRelatedProduct {
	if (!availableColors || availableColors.length === 0) {
		return product;
	}

	const randomColor = getRandomColorFromArray(availableColors);

	if (!randomColor) {
		return product;
	}

	return {
		...product,
		color: randomColor.id,
		image_src: randomColor.image_url ?? product.image_src,
	};
}

export function getRandomColorFromArray(
	colors: IProductColor[],
): IProductColor | undefined {
	if (!Boolean(colors) || colors.length === 0) {
		return undefined;
	}

	return colors[Math.floor(Math.random() * colors.length)];
}

