it('should return undefined for empty array', () => {
	const result = getRandomColorFromArray([]);
	expect(result).toBeUndefined();
});

it('should return undefined for null/undefined input', () => {
	const result = getRandomColorFromArray(null as unknown as IProductColor[]);
	expect(result).toBeUndefined();
});

it('should return a color from the array', () => {
	const colors: IProductColor[] = [
		{ id: 1, name: 'Red', rbgs: [{ R: 255, G: 0, B: 0 }] },
		{ id: 2, name: 'Blue', rbgs: [{ R: 0, G: 0, B: 255 }] },
		{ id: 3, name: 'Green', rbgs: [{ R: 0, G: 255, B: 0 }] },
	];

	const result = getRandomColorFromArray(colors);
	expect(result).toBeDefined();
	expect(colors).toContainEqual(result);
});

it('should return the single color when array has one element', () => {
	const colors: IProductColor[] = [
		{ id: 1, name: 'Red', rbgs: [{ R: 255, G: 0, B: 0 }] },
	];

	const result = getRandomColorFromArray(colors);
	expect(result).toEqual(colors[0]);
});

